exercises.solutionCode:
monthly_summary = df.groupby(
    ['category', pd.Grouper(key='date', freq='ME')]
).agg(
    total_sales=('sales', 'sum'),
    avg_sales=('sales', 'mean')
)
df['pct_of_monthly'] = (
    df['sales'] / df.groupby(
        ['category', pd.Grouper(key='date', freq='ME')]
    )['sales'].transform('sum') * 100
).round(2)

